#include <iostream>
#include <format>

int main() {
    using namespace std::chrono;
    using namespace std::chrono_literals;

    // Создаём даты двумя способами
    year_month_day today{year{2026}, month{7}, day{21}};
    auto d2 = 2026y/July/21d;  // то же самое через литералы

    std::cout << std::format("{:%Y-%m-%d}", today) << "\n";  // ISO формат
    std::cout << std::format("{:%d %B %Y}", d2) << "\n";     // текстовый месяц

    // Арифметика дат
    auto next_month = today + months{1};
    auto next_year  = today + years{1};
    std::cout << std::format("{:%Y-%m-%d}", next_month) << "\n";
    std::cout << std::format("{:%Y-%m-%d}", next_year) << "\n";

    // Последний день февраля 2026
    auto feb_last = 2026y/February/last;
    std::cout << std::format("{:%Y-%m-%d}", year_month_day{feb_last}) << "\n";

    // День недели
    sys_days sd{today};
    weekday wd{sd};
    std::cout << std::format("{}", wd) << "\n";

    // Валидация
    year_month_day invalid{year{2026}, month{2}, day{30}};
    std::cout << "2026-02-30 valid: " << invalid.ok() << "\n";
    std::cout << "2026-07-21 valid: " << today.ok() << "\n";
}

#include <chrono>
#include <iostream>
#include <format>

int main() {
    using namespace std::chrono;
    using namespace std::chrono_literals;

    // hh_mm_ss разбивает duration на компоненты
    auto duration = 3h + 45min + 30s + 123ms;
    hh_mm_ss hms{duration};
    std::cout << hms.hours().count() << "h "
              << hms.minutes().count() << "m "
              << hms.seconds().count() << "s "
              << hms.subseconds().count() << "ms\n";

    // sys_days -> year_month_day: день 100 от 1 января 2026
    sys_days sd = sys_days{year_month_day{2026y/January/1d}};
    year_month_day ymd{sd + days{100}};
    std::cout << std::format("{:%Y-%m-%d}", ymd) << "\n";  // 2026-04-11

    // Количество дней с эпохи Unix (1970-01-01)
    auto epoch_days = sd.time_since_epoch().count();
    std::cout << "days since epoch: " << epoch_days << "\n";
}

