#include <chrono>
#include <iostream>
#include <format>

int main() {
    using namespace std::chrono;

    // floor, ceil, round для duration
    milliseconds ms{1750};
    std::cout << "floor to seconds: " << floor<seconds>(ms).count() << "\n";
    std::cout << "ceil  to seconds: " << ceil<seconds>(ms).count() << "\n";
    std::cout << "round to seconds: " << round<seconds>(ms).count() << "\n";

    // Арифметика с duration
    auto d = hours{2} + minutes{30} + seconds{15};
    std::cout << "total seconds: " << duration_cast<seconds>(d).count() << "\n";
    std::cout << "total minutes: " << duration_cast<minutes>(d).count() << "\n";

    // День 180 от 1 января 2026, 9:00 UTC
    sys_days epoch{year{2026}/January/1d};
    auto event = epoch + days{180} + hours{9};
    year_month_day event_ymd{floor<days>(event)};
    std::cout << std::format("event date: {:%Y-%m-%d}", event_ymd) << "\n";

    // Сколько дней от 1 января до события?
    auto days_count = duration_cast<days>(event - epoch).count();
    std::cout << "days since Jan 1: " << days_count << "\n";

    // День недели события
    weekday wd{floor<days>(event)};
    std::cout << std::format("weekday: {}", wd) << "\n";
}

#include <chrono>
#include <iostream>
#include <format>
#include <sstream>

// Количество дней между двумя датами
int days_until(std::chrono::year_month_day from, std::chrono::year_month_day to) {
    using namespace std::chrono;
    return (sys_days{to} - sys_days{from}).count();
}

int main() {
    using namespace std::chrono;
    using namespace std::chrono_literals;

    // Парсинг даты из строки
    std::istringstream ss1{"2026-12-31"};
    year_month_day new_year_eve;
    ss1 >> parse("%Y-%m-%d", new_year_eve);
    std::cout << std::format("parsed: {:%Y-%m-%d}", new_year_eve) << "\n";

    // Парсинг даты и времени
    std::istringstream ss2{"2026-07-21 14:30:00"};
    sys_seconds tp;
    ss2 >> parse("%Y-%m-%d %H:%M:%S", tp);
    std::cout << std::format("parsed datetime: {:%Y-%m-%d %H:%M:%S}", tp) << "\n";

    // Сколько дней до 31 декабря?
    year_month_day today{year{2026}/July/21d};
    int d = days_until(today, new_year_eve);
    std::cout << "days until Dec 31: " << d << "\n";

    // День недели Рождества 2026
    year_month_day christmas{year{2026}/December/25d};
    weekday wd{sys_days{christmas}};
    std::cout << std::format("Christmas 2026: {}", wd) << "\n";

    // steady_clock для бенчмарков (монотонные, не прыгают)
    auto t0 = steady_clock::now();
    volatile long s = 0;
    for (int i = 0; i < 100000; ++i) s += i;
    auto t1 = steady_clock::now();
    auto us = duration_cast<microseconds>(t1 - t0).count();
    std::cout << "benchmark: " << (us > 0 ? "measured" : "instant") << "\n";
}
